+export function resolveLaunchAgentPlistPath(
+  env: Record<string, string | undefined>,
+): string {
+  const home = resolveHomeDir(env);
+  return path.join(
+    home,
+    "Library",
+    "LaunchAgents",
+    `${GATEWAY_LAUNCH_AGENT_LABEL}.plist`,
