+function resolveHomeDir(env: Record<string, string | undefined>): string {
+  const home = env.HOME?.trim() || env.USERPROFILE?.trim();
+  if (!home) throw new Error("Missing HOME");
+  return home;
+}
+
+function resolveSystemdUnitPath(env: Record<string, string | undefined>): string {
+  const home = resolveHomeDir(env);
+  return path.join(
+    home,
+    ".config",
+    "systemd",
+    "user",
+    `${GATEWAY_SYSTEMD_SERVICE_NAME}.service`,
+  );
+}
+
+function systemdEscapeArg(value: string): string {
+  if (!/[\s"\\]/.test(value)) return value;
+  return `"${value.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
+}
+
+function renderEnvLines(
+  env: Record<string, string | undefined> | undefined,
+): string[] {
+  if (!env) return [];
+  const entries = Object.entries(env).filter(
+    ([, value]) => typeof value === "string" && value.trim(),
+  );
+  if (entries.length === 0) return [];
+  return entries.map(
+    ([key, value]) =>
+      `Environment=${systemdEscapeArg(`${key}=${value?.trim() ?? ""}`)}`,
+  );
+}
+
+function buildSystemdUnit({
+  programArguments,
+  workingDirectory,
+  environment,
+}: {
+  programArguments: string[];
+  workingDirectory?: string;
+  environment?: Record<string, string | undefined>;
+}): string {
+  const execStart = programArguments.map(systemdEscapeArg).join(" ");
+  const workingDirLine = workingDirectory
+    ? `WorkingDirectory=${systemdEscapeArg(workingDirectory)}`
+    : null;
+  const envLines = renderEnvLines(environment);
+  return [
+    "[Unit]",
+    "Description=Clawdis Gateway",
+    "",
+    "[Service]",
+    `ExecStart=${execStart}`,
+    "Restart=always",
+    workingDirLine,
+    ...envLines,
+    "",
+    "[Install]",
+    "WantedBy=default.target",
+    "",
+  ]
+    .filter((line) => line !== null)
+    .join("\n");
+}
+
+function parseSystemdExecStart(value: string): string[] {
+  const args: string[] = [];
+  let current = "";
+  let inQuotes = false;
+  let escapeNext = false;
+
+  for (const char of value) {
+    if (escapeNext) {
+      current += char;
+      escapeNext = false;
+      continue;
+    }
+    if (char === "\\") {
+      escapeNext = true;
+      continue;
+    }
+    if (char === '"') {
+      inQuotes = !inQuotes;
+      continue;
+    }
+    if (!inQuotes && /\s/.test(char)) {
+      if (current) {
+        args.push(current);
+        current = "";
+      }
+      continue;
+    }
+    current += char;
+  }
+  if (current) args.push(current);
+  return args;
